-- Get IDs
SET @patientId = (SELECT id FROM patients WHERE email = 'john.patient@test.com' LIMIT 1);
SET @physicianId = (SELECT id FROM users WHERE role = 'admin' LIMIT 1);

-- Create care plan with snake_case columns
INSERT INTO patient_care_plans (
  patient_id, physician_id, title, diagnosis, goals, medications, lifestyle, monitoring,
  check_in_frequency, next_check_in_date, status, start_date, shared_with_patient, created_at, updated_at
)
VALUES (
  @patientId,
  @physicianId,
  'Type 2 Diabetes Management Plan',
  'Type 2 Diabetes Mellitus (E11.9)',
  JSON_ARRAY(
    'Reduce HbA1c to below 7%',
    'Lose 10-15 pounds over 3 months',
    'Exercise 30 minutes daily',
    'Monitor blood glucose twice daily'
  ),
  JSON_ARRAY(
    JSON_OBJECT('name', 'Metformin', 'dosage', '500mg', 'frequency', 'Twice daily with meals', 'instructions', 'Take with food', 'startDate', CURRENT_TIMESTAMP),
    JSON_OBJECT('name', 'Lisinopril', 'dosage', '10mg', 'frequency', 'Once daily', 'instructions', 'Take in the morning', 'startDate', CURRENT_TIMESTAMP)
  ),
  JSON_ARRAY(
    JSON_OBJECT('category', 'Diet', 'recommendation', 'Low-carb Mediterranean diet', 'frequency', 'Daily'),
    JSON_OBJECT('category', 'Exercise', 'recommendation', 'Brisk walking', 'frequency', '30 min, 5x/week')
  ),
  JSON_ARRAY(
    JSON_OBJECT('metric', 'HbA1c', 'frequency', 'Every 3 months', 'target', '<7%', 'instructions', 'Fasting blood test'),
    JSON_OBJECT('metric', 'Blood pressure', 'frequency', 'Weekly', 'target', '<130/80', 'instructions', 'Home monitoring')
  ),
  'weekly',
  DATE_ADD(NOW(), INTERVAL 7 DAY),
  'active',
  NOW(),
  1,
  NOW(),
  NOW()
);

SELECT LAST_INSERT_ID() AS care_plan_id, @patientId AS patient_id, @physicianId AS physician_id;

